#include <bits/stdc++.h>
using namespace std;
int n,h[302];
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&h[i]);
    sort(h+1,h+n+1);
    int i=1,j=n,p=0;
    long long ans=0;
    while(i<=j){
        if(p<i)
            ans+=1LL*(h[j]-h[p])*(h[j]-h[p]),p=j--;
        else
            ans+=1LL*(h[i]-h[p])*(h[i]-h[p]),p=i++;
    }
    printf("%lld",ans);
    return 0;
}
